62	static FailureOr<PaddingValueAttr>
63	parseOptionalPaddingValue(AsmParser &parser) {
64	  // Try to parse "padding_value = value"
65	  if (failed(parser.parseOptionalKeyword("padding_value")))
66	    return PaddingValueAttr();
67	
68	  SMLoc loc = parser.getCurrentLocation();
69	  StringRef paddingValueStr;
70	
71	  if (parser.parseEqual() || parser.parseKeyword(&paddingValueStr))
72	    return failure();
73	
74	  auto attr = symbolizePaddingValue(paddingValueStr);
75	  if (!attr) {
76	    return parser.emitError(loc)
77	           << "invalid padding_value attribute specification. Got \""
78	           << paddingValueStr
79	           << "\" but expect one of: zero, neg_zero, nan, pos_inf, neg_inf";
80	  }
81	
82	  return PaddingValueAttr::get(parser.getBuilder().getContext(), *attr);
83	}
