89	/// Parse a type, if type is unprefixed, assume it is from the cuda_tile dialect
90	ParseResult cuda_tile::parseCudaTileType(AsmParser &p, Type &type) {
91	  // The MLIR builtin dialect now provides a `token` type whose spelling
92	  // collides with the cuda_tile `token` mnemonic. Make sure we parse
93	  // the token as the cuda_tile token type.
94	  if (succeeded(p.parseOptionalKeyword(cuda_tile::TokenType::getMnemonic()))) {
95	    type = cuda_tile::TokenType::get(p.getContext());
96	    return success();
97	  }
98	
99	  auto result = p.parseOptionalType(type);
100	  if (result.has_value())
101	    return *result;
102	
103	  StringRef mnemonic;
104	  result = generatedTypeParser(p, &mnemonic, type);
105	  if (result.has_value())
106	    return *result;
107	
108	  return p.emitError(p.getCurrentLocation(), "unknown type: ") << mnemonic;
109	}
