111	ParseResult cuda_tile::parseCudaTileType(AsmParser &p,
112	                                         SmallVectorImpl<Type> &types) {
113	  return p.parseCommaSeparatedList(
114	      AsmParser::Delimiter::None,
115	      [&]() -> ParseResult {
116	        Type type;
117	        if (failed(parseCudaTileType(p, type)))
118	          return failure();
119	        types.push_back(type);
120	        return success();
121	      },
122	      "Expected comma separated list of types");
123	}
