125	ParseResult cuda_tile::parseCudaTileTypeSplat(
126	    AsmParser &p, SmallVectorImpl<Type> &types,
127	    ArrayRef<OpAsmParser::UnresolvedOperand> values) {
128	
129	  if (failed(parseCudaTileType(p, types.emplace_back())))
130	    return failure();
131	
132	  types.resize(values.size(), types.back());
133	  return success();
134	}
