176	Type cuda_tile::TileType::parse(AsmParser &parser) {
177	  SMLoc loc = parser.getCurrentLocation();
178	  SmallVector<int64_t> dims;
179	  Type elementType;
180	  if (parser.parseLess() ||
181	      parser.parseDimensionList(dims, /*allowDynamic=*/false) ||
182	      parseCudaTileType(parser, elementType) || parser.parseGreater())
183	    return Type();
184	  return parser.getChecked<cuda_tile::TileType>(loc, elementType.getContext(),
185	                                                dims, elementType);
186	}
