195	cuda_tile::TileType::verify(function_ref<InFlightDiagnostic()> emitError,
196	                            ArrayRef<int64_t> shape, Type elementType) {
197	  if (isa<Float4E2M1FNType>(elementType)) {
198	    // f4 must have an even number of elements to pack 2 per byte
199	    if (shape.empty() ||
200	        llvm::all_of(shape, [](int64_t dim) { return dim % 2 != 0; }))
201	      return emitError()
202	             << "F4E2M1FN tiles must have an even number of elements";
203	  }
204	  return verifyTileSize(emitError, shape);
205	}
