221	TileType cuda_tile::reshapeTileTypeToRank(TileType type, int targetRank) {
222	  int r = type.hasRank() ? type.getRank() : 0;
223	  assert(targetRank >= r);
224	  if (targetRank == r)
225	    return type;
226	  llvm::SmallVector<int64_t, 8> newShape;
227	  newShape.assign(targetRank - r, /*value=*/1);
228	  llvm::append_range(newShape, type.getShape());
229	  return cuda_tile::TileType::get(newShape, type.getElementType());
230	}
