236	/// Parses the textural representation of a tensor_view stride.
237	static ParseResult parseStrideArray(AsmParser &parser,
238	                                    SmallVectorImpl<int64_t> &stride) {
239	  auto parseStrideElem = [&]() -> ParseResult {
240	    SMLoc loc = parser.getCurrentLocation();
241	
242	    if (succeeded(parser.parseOptionalQuestion())) {
243	      stride.push_back(cuda_tile::TensorViewType::kDynamic);
244	      return success();
245	    }
246	
247	    int64_t intStride = 0;
248	    OptionalParseResult intParseResult =
249	        parser.parseOptionalInteger<int64_t>(intStride);
250	
251	    // If no hint of an integer was found.
252	    if (!intParseResult.has_value())
253	      return parser.emitError(
254	          loc, "expected either 64-bit integer or question mark");
255	
256	    // If an invalid integer was found, an error has already been printed.
257	    if (failed(intParseResult.value()))
258	      return failure();
259	
260	    // This is checked here to avoid accepting `kDynamic` as an explicit value.
261	    if (intStride <= 0)
262	      return parser.emitError(loc, "expected strictly positive integer, got ")
263	             << intStride;
264	
265	    stride.push_back(intStride);
266	    return success();
267	  };
268	
269	  return parser.parseCommaSeparatedList(AsmParser::Delimiter::Square,
270	                                        parseStrideElem, "strides array");
271	}
272	
273	Type cuda_tile::TensorViewType::parse(AsmParser &parser) {
274	  SMLoc loc = parser.getCurrentLocation();
275	  SmallVector<int64_t> shape;
276	
277	  Type elementType;
278	  if (parser.parseLess() ||
279	      parser.parseDimensionList(shape, /*allowDynamic=*/true) ||
280	      parseCudaTileType(parser, elementType))
281	    return Type();
282	
283	  // Handle strides parsing based on tensor dimensionality
284	  SmallVector<int64_t> strides;
285	
286	  if (shape.empty()) {
287	    // For 0-D tensors, check if strides are incorrectly provided
288	    if (succeeded(parser.parseOptionalComma())) {
289	      if (succeeded(parser.parseOptionalKeyword("strides"))) {
290	        parser.emitError(parser.getCurrentLocation())
291	            << "strides must not be provided for 0-d tiles";
292	        return Type();
293	      } else {
294	        // If there's a comma but no 'strides' keyword, that's also an error
295	        parser.emitError(parser.getCurrentLocation())
296	            << "unexpected token after element type in 0-d tensor_view";
297	        return Type();
298	      }
299	    }
300	  } else {
301	    // For non-0D tensors, strides are required
302	    if (failed(parser.parseOptionalComma())) {
303	      parser.emitError(parser.getCurrentLocation()) << "expected 'strides'";
304	      return Type();
305	    }
306	    if (parser.parseKeyword("strides") || parser.parseEqual() ||
307	        parseStrideArray(parser, strides))
308	      return Type();
309	  }
310	
311	  if (parser.parseGreater())
312	    return Type();
313	
314	  return parser.getChecked<cuda_tile::TensorViewType>(
315	      loc, parser.getContext(), elementType, shape, strides);
316	}
