318	void cuda_tile::TensorViewType::print(AsmPrinter &printer) const {
319	  printer << "<";
320	  printShapeAndElem(printer, getShape(), getElementType());
321	
322	  // Only print strides if tensor_view is not 0-D.
323	  if (!getShape().empty()) {
324	    printer << ", strides=[";
325	    llvm::interleave(
326	        getStrides(), printer,
327	        [&](int64_t strideElem) {
328	          if (strideElem == TensorViewType::kDynamic)
329	            printer << "?";
330	          else
331	            printer << strideElem;
332	        },
333	        ",");
334	    printer << "]";
335	  }
336	
337	  printer << ">";
338	}
