342	/// Prints an array of dimensions in diagnostics, replacing
343	/// TensorViewType::kDynamic with a question mark.
344	struct PrintDynamic {
345	  PrintDynamic(ArrayRef<int64_t> values) : values(values) {}
346	  ArrayRef<int64_t> values;
347	};
348	
349	Diagnostic &operator<<(Diagnostic &diag, PrintDynamic v) {
350	  diag << "[";
351	  llvm::interleaveComma(v.values, diag, [&](int64_t value) {
352	    if (value == cuda_tile::TensorViewType::kDynamic)
353	      diag << '?';
354	    else
355	      diag << value;
356	  });
357	  diag << "]";
358	  return diag;
359	}
