363	LogicalResult
364	cuda_tile::TensorViewType::verify(function_ref<InFlightDiagnostic()> emitError,
365	                                  Type elementType, ArrayRef<int64_t> shape,
366	                                  ArrayRef<int64_t> stride) {
367	  if (shape.size() != stride.size())
368	    return emitError() << "expected shape and stride to be of same rank but "
369	                          "got shape of rank "
370	                       << shape.size() << " and stride of rank "
371	                       << stride.size();
372	
373	  if (any_of(shape, [](int64_t dim) {
374	        return dim <= 0 && dim != cuda_tile::TensorViewType::kDynamic;
375	      }))
376	    return emitError()
377	           << "dimensions must have strictly positive constant sizes but got "
378	           << PrintDynamic(shape);
379	
380	  if (any_of(stride, [](int64_t dim) {
381	        return dim <= 0 && dim != cuda_tile::TensorViewType::kDynamic;
382	      }))
383	    return emitError()
384	           << "dimensions must have strictly positive constant strides but got "
385	           << PrintDynamic(stride);
386	
387	  return success();
388	}
