406	static ParseResult parseViewTileShape(AsmParser &parser,
407	                                      SmallVector<int32_t> &tileShape) {
408	  if (parser.parseKeyword("tile") || parser.parseEqual())
409	    return ParseResult::failure();
410	
411	  SMLoc dimListLoc = parser.getCurrentLocation();
412	
413	  SmallVector<int64_t> tileShape64;
414	  if (parser.parseLParen() ||
415	      parser.parseDimensionList(tileShape64, /*allowDynamic=*/false,
416	                                /*withTrailingX=*/false) ||
417	      parser.parseRParen())
418	    return ParseResult::failure();
419	
420	  for (auto [i, v] : llvm::enumerate(tileShape64)) {
421	    if (v <= 0 || v > std::numeric_limits<int32_t>::max()) {
422	      return parser.emitError(dimListLoc)
423	             << "tile dimension " << i << " exceeds i32 limitations (got " << v
424	             << ", expected strictly positive and less than or equal to "
425	             << std::numeric_limits<int32_t>::max() << ")";
426	    }
427	    tileShape.push_back(static_cast<int32_t>(v));
428	  }
429	
430	  return ParseResult::success();
431	}
432	
433	/// Parses an optional comma followed by a dimMap, returning the identity dimMap
434	/// if absent.
435	static ParseResult parseOptionalViewDimMap(AsmParser &parser,
436	                                           SmallVector<int32_t> &dimMap,
437	                                           size_t tileRank) {
438	  auto parseDimMapElem = [&]() -> ParseResult {
439	    int32_t dim;
440	    if (parser.parseInteger(dim))
441	      return ParseResult::failure();
442	    dimMap.push_back(dim);
443	    return ParseResult::success();
444	  };
445	
446	  if (succeeded(parser.parseOptionalComma())) {
447	    if (parser.parseKeyword("dim_map") || parser.parseEqual() ||
448	        parser.parseCommaSeparatedList(AsmParser::Delimiter::Square,
449	                                       parseDimMapElem, "dim map"))
450	      return ParseResult::failure();
451	  } else {
452	    // By default, dimMap is the identity mapping.
453	    for (int32_t i : llvm::seq(tileRank))
454	      dimMap.push_back(i);
455	  }
456	
457	  return ParseResult::success();
458	}
