460	Type cuda_tile::PartitionViewType::parse(AsmParser &parser) {
461	  SMLoc loc = parser.getCurrentLocation();
462	
463	  if (parser.parseLess())
464	    return Type();
465	
466	  SmallVector<int32_t> tileShape;
467	  if (parseViewTileShape(parser, tileShape) || parser.parseComma())
468	    return Type();
469	
470	  FailureOr<PaddingValueAttr> paddingValue = parseOptionalPaddingValue(parser);
471	  if (failed(paddingValue))
472	    return Type();
473	  else if (*paddingValue && parser.parseComma())
474	    return Type();
475	
476	  Type parsedType;
477	  if (parseCudaTileType(parser, parsedType))
478	    return Type();
479	  auto tensor_view = dyn_cast<TensorViewType>(parsedType);
480	  if (!tensor_view) {
481	    parser.emitError(parser.getCurrentLocation())
482	        << "expected 'tensor_view' type, but got " << parsedType;
483	    return Type();
484	  }
485	
486	  SmallVector<int32_t> dimMap;
487	  if (parseOptionalViewDimMap(parser, dimMap, tileShape.size()))
488	    return Type();
489	
490	  if (parser.parseGreater())
491	    return Type();
492	
493	  return parser.getChecked<cuda_tile::PartitionViewType>(
494	      loc, parser.getContext(),
495	      DenseI32ArrayAttr::get(parser.getContext(), tileShape), tensor_view,
496	      dimMap, *paddingValue);
497	}
