529	/// Verifies requirements that are shared between all grid-like views.
530	static LogicalResult verifyPartitionViewLike(
531	    function_ref<InFlightDiagnostic()> emitError,
532	    DenseI32ArrayAttr tileShapeAttr, cuda_tile::TensorViewType tensorView,
533	    ArrayRef<int32_t> dimMap, PaddingValueAttr paddingValue) {
534	  ArrayRef<int32_t> tileShape = tileShapeAttr.asArrayRef();
535	
536	  if (tileShape.empty())
537	    return emitError() << "0-dimension tile shape is not supported";
538	
539	  if (tileShape.size() != tensorView.getShape().size())
540	    return emitError() << "expected tensor_view rank and tile rank "
541	                          "to match, got tensor_view of rank "
542	                       << tensorView.getShape().size() << " and tiles of rank "
543	                       << tileShape.size();
544	
545	  if (tileShape.size() > std::numeric_limits<int32_t>::max())
546	    return emitError() << "tile rank cannot be more than "
547	                       << std::numeric_limits<int32_t>::max() << ", got "
548	                       << tileShape.size();
549	
550	  if (dimMap.size() != tileShape.size())
551	    return emitError() << "expected dim_map to map exactly all "
552	                       << tileShape.size() << " dimensions of the tile, got "
553	                       << dimMap.size() << " mappings";
554	
555	  if (any_of(tileShape, [](int32_t dim) { return dim <= 0; }))
556	    return emitError()
557	           << "tile shape dimensions must have positive length but got ["
558	           << tileShape << "]";
559	
560	  if (any_of(tileShape, [](int32_t dim) { return (dim & (dim - 1)) != 0; }))
561	    return emitError()
562	           << "tile shape dimensions must have power of two length but got ["
563	           << tileShape << "]";
564	
565	  SmallVector<std::optional<int32_t>> usedTensorViewDim(tileShape.size(),
566	                                                        std::nullopt);
567	  for (auto [tileDim, tensorViewDim] : llvm::enumerate(dimMap)) {
568	    if (tensorViewDim < 0)
569	      return emitError() << "target dimension must not be negative, got "
570	                         << tensorViewDim;
571	
572	    if (static_cast<uint32_t>(tensorViewDim) >= tensorView.getShape().size())
573	      return emitError()
574	             << "target dimension is outside of tensor view dimensions, "
575	                "expected strictly less than "
576	             << tensorView.getShape().size() << ", got " << tensorViewDim;
577	
578	    if (usedTensorViewDim[tensorViewDim].has_value())
579	      return emitError() << "target dimension " << tensorViewDim
580	                         << " mapped at least twice (for tile dimensions "
581	                         << usedTensorViewDim[tensorViewDim].value() << " and "
582	                         << tileDim << ")";
583	
584	    usedTensorViewDim[tensorViewDim] = tileDim;
585	  }
586	
587	  // Run the Tile type verifier to catch invalid tiles in the partition type
588	  SmallVector<int64_t> shape64(tileShape.begin(), tileShape.end());
589	  if (failed(cuda_tile::TileType::verify([&]() { return emitError(); }, shape64,
590	                                         tensorView.getElementType())))
591	    return failure();
592	
593	  // Verify that special padding values are only used with floating point types
594	  if (paddingValue) {
595	    switch (paddingValue.getValue()) {
596	    default:
597	      break;
598	    case PaddingValue::neg_zero:
599	    case PaddingValue::nan:
600	    case PaddingValue::pos_inf:
601	    case PaddingValue::neg_inf:
602	      if (!llvm::isa<FloatType>(tensorView.getElementType()))
603	        return emitError()
604	               << "padding_value "
605	               << stringifyPaddingValue(paddingValue.getValue())
606	               << " can only be used with floating point element types, got "
607	               << tensorView.getElementType();
608	      break;
609	    }
610	  }
611	
612	  return success();
613	}
