615	LogicalResult cuda_tile::PartitionViewType::verify(
616	    function_ref<InFlightDiagnostic()> emitError,
617	    DenseI32ArrayAttr tileShapeAttr, cuda_tile::TensorViewType tensorView,
618	    ArrayRef<int32_t> dimMap, PaddingValueAttr paddingValue) {
619	  return verifyPartitionViewLike(emitError, tileShapeAttr, tensorView, dimMap,
620	                                 paddingValue);
