634	LogicalResult cuda_tile::PartitionViewType::verifyIndices(
635	    function_ref<InFlightDiagnostic()> emitError, TypeRange indexTypes) const {
636	  if (indexTypes.empty())
637	    return success();
638	
639	  // All indices must be scalar tiles.
640	  for (Type t : indexTypes) {
641	    auto tileType = dyn_cast<TileType>(t);
642	    if (!tileType) {
643	      return emitError() << "expected index type to be a tile type, got " << t;
644	    }
645	    if (tileType.getRank() != 0) {
646	      return emitError() << "expected index type to be a scalar tile, got "
647	                         << tileType;
648	    }
649	  }
650	
651	  // All indices must have the same type.
652	  Type baseIndexType = indexTypes.front();
653	  for (const auto &[i, indexType] : llvm::enumerate(indexTypes)) {
654	    if (indexType != baseIndexType)
655	      return emitError() << "expected index type " << i
656	                         << " to be the same as other index types ("
657	                         << baseIndexType << "), got " << indexType;
658	  }
659	  return success();
660	}
