666	static ParseResult
667	parseViewTraversalStrides(AsmParser &parser,
668	                          SmallVector<int32_t> &traversalStrides) {
669	  if (parser.parseKeyword("traversal_strides") || parser.parseEqual())
670	    return ParseResult::failure();
671	
672	  auto parseStrideElement = [&]() {
673	    int32_t element;
674	    ParseResult result = parser.parseInteger(element);
675	    if (succeeded(result))
676	      traversalStrides.push_back(element);
677	    return result;
678	  };
679	
680	  return parser.parseCommaSeparatedList(AsmParser::Delimiter::Square,
681	                                        parseStrideElement);
682	}
