685	  SMLoc loc = parser.getCurrentLocation();
686	
687	  if (parser.parseLess())
688	    return Type();
689	
690	  SmallVector<int32_t> tileShape;
691	  SmallVector<int32_t> traversalStrides;
692	  if (parseViewTileShape(parser, tileShape) || parser.parseComma() ||
693	      parseViewTraversalStrides(parser, traversalStrides) ||
694	      parser.parseComma())
695	    return Type();
696	
697	  FailureOr<PaddingValueAttr> paddingValue = parseOptionalPaddingValue(parser);
698	  if (failed(paddingValue))
699	    return Type();
700	  else if (*paddingValue && parser.parseComma())
701	    return Type();
702	
703	  Type parsedType;
704	  if (parseCudaTileType(parser, parsedType))
705	    return Type();
706	  auto tensor_view = dyn_cast<TensorViewType>(parsedType);
707	  if (!tensor_view) {
708	    parser.emitError(parser.getCurrentLocation())
709	        << "expected 'tensor_view' type, but got " << parsedType;
710	    return Type();
711	  }
712	
713	  SmallVector<int32_t> dimMap;
714	  if (parseOptionalViewDimMap(parser, dimMap, tileShape.size()))
715	    return Type();
716	
717	  if (parser.parseGreater())
718	    return Type();
719	
720	  return parser.getChecked<cuda_tile::StridedViewType>(
721	      loc, parser.getContext(),
722	      DenseI32ArrayAttr::get(parser.getContext(), tileShape),
723	      DenseI32ArrayAttr::get(parser.getContext(), traversalStrides),
724	      tensor_view, dimMap, *paddingValue);
725	}
