838	    return Type();
839	  auto tensor_view = dyn_cast<TensorViewType>(parsedType);
840	  if (!tensor_view) {
841	    parser.emitError(parser.getCurrentLocation())
842	        << "expected 'tensor_view' type, but got " << parsedType;
843	    return Type();
844	  }
845	
846	  uint32_t sparse_dim;
847	  if (parser.parseComma() || parser.parseKeyword("sparse_dim") ||
848	      parser.parseEqual())
849	    return Type();
850	
851	  if (parser.parseInteger(sparse_dim))
852	    return Type();
853	
854	  if (parser.parseGreater())
855	    return Type();
856	
857	  SmallVector<int32_t> tileShape32;
858	  for (auto [i, v] : llvm::enumerate(tileShape)) {
859	    if (v <= 0 || v > std::numeric_limits<int32_t>::max()) {
860	      parser.emitError(dimListLoc)
861	          << "tile dimension " << i << " exceeds i32 limitations (got " << v
862	          << ", expected strictly positive and less than or equal to "
863	          << std::numeric_limits<int32_t>::max() << ")";
864	      return Type();
865	    }
866	    tileShape32.push_back(static_cast<int32_t>(v));
867	  }
868	
869	  return parser.getChecked<cuda_tile::GatherScatterViewType>(
870	      loc, parser.getContext(),
871	      DenseI32ArrayAttr::get(parser.getContext(), tileShape32), tensor_view,
872	      sparse_dim, *paddingValue);
873	}
874	
875	void cuda_tile::GatherScatterViewType::print(AsmPrinter &printer) const {
876	  printer << "<";
877	  printer << "tile=(";
878	  llvm::interleave(getTileShape().asArrayRef(), printer, "x");
879	  printer << "), ";
880	  if (getPaddingValue())
881	    printer << "padding_value = "
882	            << stringifyPaddingValue(getPaddingValue().getValue()) << ", ";
883	
884	  printCudaTileType(printer, getTensorView());
885	
886	  printer << ", sparse_dim=" << getSparseDim();
887	
888	  printer << ">";
889	}
890	
891	LogicalResult cuda_tile::GatherScatterViewType::verify(
892	    function_ref<InFlightDiagnostic()> emitError,
893	    DenseI32ArrayAttr tileShapeAttr, cuda_tile::TensorViewType tensorView,
894	    uint32_t sparse_dim, PaddingValueAttr paddingValue) {
895	  ArrayRef<int32_t> tileShape = tileShapeAttr.asArrayRef();
896	
897	  if (tileShape.empty())
898	    return emitError() << "0-dimension tile shape is not supported";
899	
900	  if (tileShape.size() != tensorView.getShape().size())
901	    return emitError() << "expected tensor_view rank and tile rank "
902	                          "to match, got tensor_view of rank "
903	                       << tensorView.getShape().size() << " and tiles of rank "
904	                       << tileShape.size();
905	
906	  if (tileShape.size() > std::numeric_limits<int32_t>::max())
907	    return emitError() << "tile rank cannot be more than "
908	                       << std::numeric_limits<int32_t>::max() << ", got "
909	                       << tileShape.size();
910	
911	  if (any_of(tileShape, [](int32_t d) { return d <= 0; }))
912	    return emitError()
913	           << "tile shape dimensions must have positive length but got ["
914	           << tileShape << "]";
915	
916	  if (any_of(tileShape, [](int32_t d) { return (d & (d - 1)) != 0; }))
917	    return emitError()
918	           << "tile shape dimensions must have power of two length but got ["
919	           << tileShape << "]";
920	
921	  // Verify sparse_dim parameter
922	  if (sparse_dim >= tensorView.getShape().size())
923	    return emitError()
924	           << "gather dimension is outside of tensor view dimensions, "
925	              "expected strictly less than "
926	           << tensorView.getShape().size() << ", got " << sparse_dim;
927	
928	  // Run the Tile type verifier to catch invalid tiles in the gather type
929	  SmallVector<int64_t> shape64(tileShape.begin(), tileShape.end());
930	  if (failed(cuda_tile::TileType::verify([&]() { return emitError(); }, shape64,
931	                                         tensorView.getElementType())))
932	    return failure();
933	
934	  // Verify that special padding values are only used with floating point types
935	  if (paddingValue) {
936	    switch (paddingValue.getValue()) {
937	    default:
938	      break;
939	    case PaddingValue::neg_zero:
940	    case PaddingValue::nan:
941	    case PaddingValue::pos_inf:
942	    case PaddingValue::neg_inf:
943	      if (!llvm::isa<FloatType>(tensorView.getElementType()))
944	        return emitError()
945	               << "padding_value "
946	               << stringifyPaddingValue(paddingValue.getValue())
947	               << " can only be used with floating point element types, got "
948	               << tensorView.getElementType();
949	      break;
950	    }
951	  }
952	
953	  return success();
954	}
955	
956	size_t cuda_tile::GatherScatterViewType::getViewIndexRank() const {
957	  return getTileShape().size();
958	}
959	
960	Type cuda_tile::GatherScatterViewType::getViewTileType() const {
961	  SmallVector<int64_t> shape64(getTileShape().size());
962	  llvm::transform(getTileShape().asArrayRef(), shape64.begin(),
963	                  [](int32_t x) -> int64_t { return x; });
964	  return cuda_tile::TileType::get(shape64, getTensorView().getElementType());
965	}
966	
967	LogicalResult cuda_tile::GatherScatterViewType::verifyIndices(
968	    function_ref<InFlightDiagnostic()> emitError, TypeRange indexTypes) const {
969	  // For GatherScatterView, the index at position `sparse_dim` MUST be a 1D
970	  // tensor (gather/scatter indices) while the rest MUST be scalar tiles.
971	  if (indexTypes.empty())
972	    return success();
973	
974	  uint32_t sparse_dim = getSparseDim();
975	
976	  // Verify sparse_dim is within index range
977	  if (sparse_dim >= indexTypes.size())
978	    return emitError() << "gather/scatter dimension " << sparse_dim
979	                       << " is out of range for index count "
980	                       << indexTypes.size();
981	
982	  // Verify index at sparse_dim position is a 1D tensor
983	  auto gatherIndexTileType = dyn_cast<TileType>(indexTypes[sparse_dim]);
984	  if (!gatherIndexTileType)
985	    return emitError() << "expected index at sparse_dim position " << sparse_dim
986	                       << " to be a tile type for GatherScatterView";
987	
988	  if (gatherIndexTileType.getShape().size() != 1)
989	    return emitError() << "expected index at sparse_dim position " << sparse_dim
990	                       << " to be a 1D tensor for GatherScatterView, got rank "
991	                       << gatherIndexTileType.getShape().size();
992	
993	  // Verify that the gather/scatter index size matches the tile shape at the
994	  // gather dimension
995	  int64_t gatherIndexSize = gatherIndexTileType.getShape()[0];
996	  int32_t tileSizeAtDim = getTileShape()[sparse_dim];
997	  if (gatherIndexSize != tileSizeAtDim)
998	    return emitError() << "expected gather/scatter index size ("
999	                       << gatherIndexSize
1000	                       << ") to match tile shape at gather/scatter dimension "
1001	                       << sparse_dim << " (" << tileSizeAtDim << ")";
1002	
1003	  // Verify all other indices are scalar tiles and have the same type
1004	  Type baseScalarType;
1005	  for (size_t i = 0; i < indexTypes.size(); ++i) {
1006	    if (i == sparse_dim)
1007	      continue; // Skip the gather index
1008	
1009	    auto idxTileType = dyn_cast<TileType>(indexTypes[i]);
1010	    if (!idxTileType || !idxTileType.getShape().empty())
1011	      return emitError() << "expected index " << i
1012	                         << " to be a scalar tile for GatherScatterView";
1013	
1014	    if (!baseScalarType) {
1015	      baseScalarType = indexTypes[i];
1016	    } else if (indexTypes[i] != baseScalarType) {
1017	      return emitError() << "expected scalar index " << i
1018	                         << " to have the same type as other scalar indices ("
1019	                         << baseScalarType << "), got " << indexTypes[i];
1020	    }
1021	  }
1022	
1023	  return success();
1024	}
