// Type Registration
//===----------------------------------------------------------------------===//

void CudaTileDialect::registerTypes() {
  addTypes<
#define GET_TYPEDEF_LIST
#include "cuda_tile/Dialect/CudaTile/IR/Types.cpp.inc"
      >();
}

